import express from 'express';
import { Request, Response } from 'express';
import { exec } from 'child_process';
import { promises as fs } from 'fs';
import path from 'path';
import os from 'os';
import { v4 as uuidv4 } from 'uuid';
import { promisify } from 'util';
import bodyParser from 'body-parser';

const execPromise = promisify(exec);

const app = express();
const port = 3000;

app.use(bodyParser.json());

// Define the path to the compiled Puppeteer script
// In a production environment, you would typically compile generatePdfScript.ts to generatePdfScript.js
// and ensure it's accessible.
const PUPPETEER_SCRIPT_PATH = path.join(__dirname, 'generatePdfScript.js');

app.post('/generate-pdf', async (req: Request, res: Response) => {
  const { url, filename } = req.body;

  if (!url || typeof url !== 'string') {
    return res.status(400).json({ error: 'Missing or invalid "url" in request body.' });
  }

  if (!filename || typeof filename !== 'string') {
    return res.status(400).json({ error: 'Missing or invalid "filename" in request body.' });
  }

  // Sanitize filename to prevent directory traversal or invalid characters
  const sanitizedFilename = path.basename(filename).replace(/[^a-zA-Z0-9_.-]/g, '_');
  if (!sanitizedFilename) {
    return res.status(400).json({ error: 'Filename cannot be empty after sanitization.' });
  }

  const outputFileName = `${uuidv4()}_${sanitizedFilename}`;
  const tempFilePath = path.join(os.tmpdir(), outputFileName);

  console.log(`Generating PDF for URL: ${url} to temp path: ${tempFilePath}`);

  try {
    // Construct the command to execute the Puppeteer script
    // We pass URL and output path as JSON strings to safely handle special characters and prevent command injection.
    const command = `node "${PUPPETEER_SCRIPT_PATH}" "${JSON.stringify(url)}" "${JSON.stringify(tempFilePath)}"`;

    console.log(`Executing command: ${command}`);

    const { stdout, stderr } = await execPromise(command, { timeout: 60000 }); // 60-second timeout for PDF generation

    if (stdout) console.log(`Puppeteer stdout: ${stdout}`);
    if (stderr) console.error(`Puppeteer stderr: ${stderr}`);

    // Check if the file was actually created
    await fs.access(tempFilePath);

    // Read the generated PDF file
    const pdfBuffer = await fs.readFile(tempFilePath);

    // Set headers for PDF download
    res.setHeader('Content-Type', 'application/pdf');
    res.setHeader('Content-Disposition', `attachment; filename="${sanitizedFilename}.pdf"`);
    res.send(pdfBuffer);

    console.log(`PDF successfully generated and sent for ${url}`);
  } catch (error: any) {
    console.error(`Error generating PDF for ${url}:`, error);
    if (error.code === 'ENOENT' && error.path === PUPPETEER_SCRIPT_PATH) {
      return res.status(500).json({
        error: 'Puppeteer script not found. Ensure generatePdfScript.js is compiled and accessible.',
        details: error.message
      });
    }
    if (error.code === 'ENOENT' && error.path === tempFilePath) {
      return res.status(500).json({
        error: 'Generated PDF file not found, Puppeteer script might have failed silently or crashed.',
        details: error.message
      });
    }
    res.status(500).json({
      error: 'Failed to generate PDF report.',
      details: error.message,
      stdout: error.stdout, // Include child process output for debugging
      stderr: error.stderr
    });
  } finally {
    // Clean up the temporary file
    try {
      await fs.unlink(tempFilePath);
      console.log(`Cleaned up temporary file: ${tempFilePath}`);
    } catch (cleanupError) {
      console.error(`Error cleaning up temporary file ${tempFilePath}:`, cleanupError);
    }
  }
});

app.listen(port, () => {
  console.log(`PDF generation microservice listening at http://localhost:${port}`);
  console.log('To use, send a POST request to /generate-pdf with JSON body:');
  console.log('{ "url": "https://example.com", "filename": "my-report" }');
});

